package com.trademaster.ims.mobile.checkout.model;
import jakarta.persistence.*;import java.math.BigDecimal;import java.time.Instant;
@Entity @Table(name="delivery_methods") public class DeliveryMethod{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(nullable=false,unique=true,length=50)private String code;@Column(nullable=false,length=100)private String name;@Column(length=250)private String description;@Column(nullable=false)private boolean active=true;@Column(name="delivery_charge",nullable=false,precision=15,scale=2)private BigDecimal charge=BigDecimal.ZERO;@Column(name="estimated_min_days",nullable=false)private int minDays;@Column(name="estimated_max_days",nullable=false)private int maxDays;@Column(name="supported_country",nullable=false,length=80)private String country="Bangladesh";@Column(name="supported_division",length=100)private String division;@Column(name="supported_district",length=100)private String district;@Column(name="minimum_order_amount",precision=15,scale=2)private BigDecimal minimum;@Column(name="maximum_order_amount",precision=15,scale=2)private BigDecimal maximum;@Column(name="created_at")private Instant createdAt;@Column(name="updated_at")private Instant updatedAt;@PrePersist void c(){createdAt=updatedAt=Instant.now();}@PreUpdate void u(){updatedAt=Instant.now();}
 public Long getId(){return id;}public String getCode(){return code;}public void setCode(String v){code=v;}public String getName(){return name;}public void setName(String v){name=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public boolean isActive(){return active;}public void setActive(boolean v){active=v;}public BigDecimal getCharge(){return charge;}public void setCharge(BigDecimal v){charge=v;}public int getMinDays(){return minDays;}public void setMinDays(int v){minDays=v;}public int getMaxDays(){return maxDays;}public void setMaxDays(int v){maxDays=v;}public String getCountry(){return country;}public void setCountry(String v){country=v;}public String getDivision(){return division;}public void setDivision(String v){division=v;}public String getDistrict(){return district;}public void setDistrict(String v){district=v;}public BigDecimal getMinimum(){return minimum;}public void setMinimum(BigDecimal v){minimum=v;}public BigDecimal getMaximum(){return maximum;}public void setMaximum(BigDecimal v){maximum=v;}}
